{
  "name": "Ruslan Market",
  "description": "Premium modern Pinduoduo shopping portal with gold and white aesthetics.",
  "requestFramePermissions": []
}

export interface Product {
  id: string;
  name: string;
  pinduoduoPrice: number; // The base price
  description: string;
  category: string;
  images: string[];
  rating: number;
  salesCount: number;
  seller: {
    name: string;
    avatar: string;
    rating: number;
    description: string;
  };
}

export interface Question {
  id: string;
  user: string;
  text: string;
  answer?: string;
  date: string;
}

export type View = 'home' | 'catalog' | 'search' | 'profile' | 'detail';

import React, { useState, useMemo } from 'react';
import { 
  Home, 
  Search, 
  Grid, 
  User, 
  ShoppingCart, 
  Star, 
  ChevronLeft, 
  MessageCircle, 
  Share2, 
  Send,
  Instagram,
  UserCheck
} from 'lucide-react';
import { Product, View, Question } from './types';
import { PRODUCTS, MARKUP_RATE } from './constants';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('home');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Local state for questions to simulate interactive Q&A
  const [questions, setQuestions] = useState<Record<string, Question[]>>({
    'p1': [
      { id: 'q1', user: 'Aziz', text: 'Yetkazib berish necha kun davom etadi?', answer: 'O\'rtacha 14-20 kun.', date: '2024-05-10' },
      { id: 'q2', user: 'Malika', text: 'Ranglari bormi?', answer: 'Ha, ko\'k va kulrang turlari ham mavjud.', date: '2024-05-12' }
    ]
  });

  const filteredProducts = useMemo(() => {
    return PRODUCTS.filter(p => 
      p.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      p.category.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [searchQuery]);

  const navigateToDetail = (product: Product) => {
    setSelectedProduct(product);
    setCurrentView('detail');
    window.scrollTo(0, 0);
  };

  const addQuestion = (productId: string, text: string) => {
    if (!text.trim()) return;
    const newQ: Question = {
      id: Math.random().toString(36).substr(2, 9),
      user: 'Mehmon',
      text,
      date: new Date().toISOString().split('T')[0]
    };
    setQuestions(prev => ({
      ...prev,
      [productId]: [newQ, ...(prev[productId] || [])]
    }));
  };

  return (
    <div className="min-h-screen pb-24 bg-[#F8F9FA]">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-white/90 backdrop-blur-md px-6 py-4 border-b border-gray-100 flex justify-between items-center shadow-sm">
        <div className="flex items-center space-x-2">
          <div className="w-8 h-8 gold-gradient rounded-lg shadow-premium"></div>
          <h1 className="font-serif text-2xl tracking-tight gold-text">Ruslan Market</h1>
        </div>
        <div className="flex space-x-4 text-gray-400">
          <Search size={22} className="cursor-pointer hover:text-amber-600 transition-colors" onClick={() => setCurrentView('search')} />
          <div className="relative cursor-pointer hover:text-amber-600 transition-colors">
            <ShoppingCart size={22} />
            <span className="absolute -top-2 -right-2 bg-red-500 text-white text-[10px] w-4 h-4 rounded-full flex items-center justify-center font-bold">3</span>
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="max-w-md mx-auto fade-in">
        {currentView === 'home' && <HomeView onProductClick={navigateToDetail} />}
        {currentView === 'catalog' && <CatalogView products={PRODUCTS} onProductClick={navigateToDetail} />}
        {currentView === 'search' && (
          <SearchView 
            query={searchQuery} 
            setQuery={setSearchQuery} 
            results={filteredProducts} 
            onProductClick={navigateToDetail} 
          />
        )}
        {currentView === 'profile' && <ProfileView />}
        {currentView === 'detail' && selectedProduct && (
          <DetailView 
            product={selectedProduct} 
            onBack={() => setCurrentView('catalog')}
            questions={questions[selectedProduct.id] || []}
            onAddQuestion={(text) => addQuestion(selectedProduct.id, text)}
          />
        )}
      </main>

      {/* Bottom Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 glass-nav h-20 flex justify-around items-center px-6 z-50">
        <NavButton icon={<Home size={24} />} label="Asosiy" active={currentView === 'home'} onClick={() => setCurrentView('home')} />
        <NavButton icon={<Grid size={24} />} label="Katalog" active={currentView === 'catalog'} onClick={() => setCurrentView('catalog')} />
        <NavButton icon={<Search size={24} />} label="Qidiruv" active={currentView === 'search'} onClick={() => setCurrentView('search')} />
        <NavButton icon={<User size={24} />} label="Profil" active={currentView === 'profile'} onClick={() => setCurrentView('profile')} />
      </nav>
    </div>
  );
};

/* Sub-components */

const NavButton = ({ icon, label, active, onClick }: { icon: any, label: string, active: boolean, onClick: () => void }) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center space-y-1 transition-all duration-300 ${active ? 'text-amber-600 scale-110' : 'text-gray-400 hover:text-gray-600'}`}
  >
    {icon}
    <span className="text-[10px] font-bold uppercase tracking-widest">{label}</span>
    {active && <div className="w-1 h-1 bg-amber-600 rounded-full"></div>}
  </button>
);

const HomeView = ({ onProductClick }: { onProductClick: (p: Product) => void }) => (
