export interface Product {
  id: string;
  name: string;
  pinduoduoPrice: number; // The base price
  description: string;
  category: string;
  images: string[];
  rating: number;
  salesCount: number;
  seller: {
    name: string;
    avatar: string;
    rating: number;
    description: string;
  };
}

export interface Question {
  id: string;
  user: string;
  text: string;
  answer?: string;
  date: string;
}

export interface User {
  username: string;
  phone: string;
  isAdmin: boolean;
}

export type View = 'home' | 'catalog' | 'search' | 'profile' | 'detail' | 'auth' | 'admin' | 'verify';

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Home, 
  Search, 
  Grid, 
  User as UserIcon, 
  ShoppingCart, 
  Star, 
  ChevronLeft, 
  MessageCircle, 
  Share2, 
  Send,
  Instagram,
  UserCheck,
  Plus,
  Lock,
  LogOut,
  Save,
  Trash2,
  Camera,
  X,
  Phone,
  ShieldCheck
} from 'lucide-react';
import { Product, View, Question, User } from './types';
import { INITIAL_PRODUCTS, MARKUP_RATE } from './constants';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('auth');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [tempAuthData, setTempAuthData] = useState<{username: string, phone: string, password?: string} | null>(null);

  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('ruslan_user');
    return saved ? JSON.parse(saved) : null;
  });

  // Product persistence
  const [allProducts, setAllProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('ruslan_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  useEffect(() => {
    localStorage.setItem('ruslan_products', JSON.stringify(allProducts));
  }, [allProducts]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('ruslan_user', JSON.stringify(currentUser));
      if (currentView === 'auth' || currentView === 'verify') setCurrentView('home');
    } else {
      localStorage.removeItem('ruslan_user');
      setCurrentView('auth');
    }
  }, [currentUser]);

  // Questions persistence
  const [questions, setQuestions] = useState<Record<string, Question[]>>(() => {
    const saved = localStorage.getItem('ruslan_questions');
    return saved ? JSON.parse(saved) : {};
  });

  useEffect(() => {
    localStorage.setItem('ruslan_questions', JSON.stringify(questions));
  }, [questions]);

  const filteredProducts = useMemo(() => {
    return allProducts.filter(p => 
      p.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      p.category.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [searchQuery, allProducts]);

  const navigateToDetail = (product: Product) => {
    setSelectedProduct(product);
    setCurrentView('detail');
    window.scrollTo(0, 0);
  };

  const addQuestion = (productId: string, text: string) => {
    if (!text.trim()) return;
    const newQ: Question = {
      id: Math.random().toString(36).substr(2, 9),
      user: currentUser?.username || 'Mehmon',
      text,
      date: new Date().toISOString().split('T')[0]
    };
    setQuestions(prev => ({
      ...prev,
      [productId]: [newQ, ...(prev[productId] || [])]
    }));
  };

  const addProduct = (newProduct: Partial<Product>) => {
    const p: Product = {
      id: 'p' + (allProducts.length + Date.now()),
      name: newProduct.name || 'Nomsiz Mahsulot',
      pinduoduoPrice: newProduct.pinduoduoPrice || 0,
      description: newProduct.description || '',
      category: newProduct.category || 'Mebel',
      images: newProduct.images && newProduct.images.length > 0 ? newProduct.images : ['https://picsum.photos/seed/new/800/600'],
      rating: 5.0,
      salesCount: 0,
      seller: {
        name: 'Ruslan Market Admin',
        avatar: 'https://i.pravatar.cc/150?u=admin',
        rating: 5.0,
        description: 'Rasmiy do\'kon xodimi.'
      }
    };
    setAllProducts([p, ...allProducts]);
    setCurrentView('catalog');
  };

  const logout = () => {
    setCurrentUser(null);
    setCurrentView('auth');
  };

  const handleStartAuth = (data: {username: string, phone: string, password?: string}) => {
    setTempAuthData(data);
    setCurrentView('verify');
  };

  const handleVerify = (code: string) => {
    // Simulated verification
    if (code === '1234' || code === '2011') {
      const isAdmin = tempAuthData?.username === 'admin' && tempAuthData?.phone === '+998943012687';
      setCurrentUser({
        username: tempAuthData?.username || 'user',
        phone: tempAuthData?.phone || '',
        isAdmin
      });
    } else {
      alert('Kod xato! Qaytadan urinib ko\'ring. (Simulatsiya kodi: 1234)');
    }
  };

  return (
    <div className="min-h-screen pb-24 bg-[#F8F9FA]">
      {currentUser && (
        <header className="sticky top-0 z-50 bg-white/90 backdrop-blur-md px-6 py-4 border-b border-gray-100 flex justify-between items-center shadow-sm">
          <div className="flex items-center space-x-2" onClick={() => setCurrentView('home')}>
            <div className="w-8 h-8 gold-gradient rounded-lg shadow-premium"></div>
            <h1 className="font-serif text-2xl tracking-tight gold-text cursor-pointer">Ruslan Market</h1>
          </div>
          <div className="flex space-x-4 text-gray-400">
            {currentUser?.isAdmin && (
              <Plus size={22} className="cursor-pointer text-amber-600" onClick={() => setCurrentView('admin')} />
            )}
            <Search size={22} className="cursor-pointer hover:text-amber-600 transition-colors" onClick={() => setCurrentView('search')} />
            <div className="relative cursor-pointer hover:text-amber-600 transition-colors" onClick={() => setCurrentView('catalog')}>
              <ShoppingCart size={22} />
            </div>
          </div>
        </header>
      )}

      <main className="max-w-md mx-auto fade-in">
        {currentView === 'auth' && <AuthView onStart={handleStartAuth} />}
        {currentView === 'verify' && <VerifyView phone={tempAuthData?.phone || ''} onVerify={handleVerify} onBack={() => setCurrentView('auth')} />}

        {currentUser && (
          <>
            {currentView === 'home' && <HomeView onProductClick={navigateToDetail} products={allProducts} />}
            {currentView === 'catalog' && <CatalogView products={allProducts} onProductClick={navigateToDetail} />}
            {currentView === 'search' && (
              <SearchView 
                query={searchQuery} 
                setQuery={setSearchQuery} 
                results={filteredProducts} 
                onProductClick={navigateToDetail} 
              />
            )}
            {currentView === 'profile' && <ProfileView user={currentUser} onLogout={logout} onAdminClick={() => setCurrentView('admin')} />}
            {currentView === 'detail' && selectedProduct && (
              <DetailView 
                product={selectedProduct} 
                onBack={() => setCurrentView('catalog')}
                questions={questions[selectedProduct.id] || []}
                onAddQuestion={(text) => addQuestion(selectedProduct.id, text)}
              />
            )}
            {currentView === 'admin' && currentUser?.isAdmin && (
              <AdminPanel onAdd={addProduct} onCancel={() => setCurrentView('catalog')} />
            )}
          </>
        )}
      </main>

      {currentUser && (
        <nav className="fixed bottom-0 left-0 right-0 glass-nav h-20 flex justify-around items-center px-6 z-50">
          <NavButton icon={<Home size={24} />} label="Asosiy" active={currentView === 'home'} onClick={() => setCurrentView('home')} />
          <NavButton icon={<Grid size={24} />} label="Katalog" active={currentView === 'catalog'} onClick={() => setCurrentView('catalog')} />
          <NavButton icon={<Search size={24} />} label="Qidiruv" active={currentView === 'search'} onClick={() => setCurrentView('search')} />
          <NavButton icon={<UserIcon size={24} />} label="Profil" active={currentView === 'profile'} onClick={() => setCurrentView('profile')} />
        </nav>
      )}
    </div>
  );
};

