const AdminPanel = ({ onAdd, onCancel }: { onAdd: (p: Partial<Product>) => void, onCancel: () => void }) => {
  const [formData, setFormData] = useState<Partial<Product>>({
    name: '',
    pinduoduoPrice: 0,
    description: '',
    category: 'Mebel',
    images: []
  });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({
          ...prev,
          images: [...(prev.images || []), reader.result as string]
        }));
      };
      reader.readAsDataURL(file);
    });
  };

  const removeImage = (index: number) => {
    setFormData(prev => ({
      ...prev,
      images: prev.images?.filter((_, i) => i !== index)
    }));
  };

  return (
    <div className="p-6 pb-32 space-y-6">
      <div className="flex items-center space-x-4">
        <button onClick={onCancel} className="text-gray-400"><ChevronLeft size={24} /></button>
        <h2 className="text-2xl font-bold">Mahsulot Qo'shish</h2>
      </div>

      <div className="space-y-6">
        <div>
          <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block mb-4">Mahsulot Rasmlari</label>
          <div className="grid grid-cols-3 gap-3">
            {formData.images?.map((img, i) => (
              <div key={i} className="relative aspect-square rounded-xl overflow-hidden group shadow-sm">
                <img src={img} className="w-full h-full object-cover" />
                <button 
                  onClick={() => removeImage(i)}
                  className="absolute top-1 right-1 bg-black/50 text-white rounded-full p-1 hover:bg-red-500 transition-colors"
                >
                  <X size={14} />
                </button>
              </div>
            ))}
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="aspect-square border-2 border-dashed border-gray-200 rounded-xl flex flex-col items-center justify-center text-gray-400 hover:border-amber-400 hover:text-amber-500 transition-all bg-white"
            >
              <Camera size={24} />
              <span className="text-[10px] mt-2 font-bold uppercase">Rasm qo'shish</span>
            </button>
          </div>
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            multiple 
            accept="image/*" 
            className="hidden" 
          />
        </div>

        <div className="space-y-4">
