const AdminPanel = ({ onAdd, onCancel }: { onAdd: (p: Partial<Product>) => void, onCancel: () => void }) => {
  const [formData, setFormData] = useState<Partial<Product>>({
    name: '',
    pinduoduoPrice: 0,
    description: '',
    category: 'Mebel',
    images: []
  });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach(file => {
      // Basic check for image types, favoring PNG
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({
          ...prev,
          images: [...(prev.images || []), reader.result as string]
        }));
      };
      reader.readAsDataURL(file);
    });
  };

  const removeImage = (index: number) => {
    setFormData(prev => ({
      ...prev,
      images: prev.images?.filter((_, i) => i !== index)
    }));
  };

  const handleSave = () => {
    if (!formData.name || !formData.pinduoduoPrice || !formData.images?.length) {
      alert("Iltimos barcha ma'lumotlarni to'ldiring (Nomi, Narxi va kamida 1 ta rasm)");
      return;
    }
    onAdd(formData);
  };

  return (
    <div className="p-6 pb-32 space-y-6">
      <div className="flex items-center space-x-4">
        <button onClick={onCancel} className="text-gray-400"><ChevronLeft size={24} /></button>
        <h2 className="text-2xl font-bold">Mahsulot Qo'shish</h2>
      </div>

      <div className="space-y-6">
        <div>
          <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block mb-4 px-1">Mahsulot Rasmlari (PNG tavsiya etiladi)</label>
          <div className="grid grid-cols-3 gap-3">
            {formData.images?.map((img, i) => (
              <div key={i} className="relative aspect-square rounded-xl overflow-hidden group shadow-sm bg-white border border-gray-100">
                <img src={img} className="w-full h-full object-contain" />
                <button 
                  onClick={() => removeImage(i)}
                  className="absolute top-1 right-1 bg-black/50 text-white rounded-full p-1 hover:bg-red-500 transition-colors"
                >
                  <X size={14} />
                </button>
              </div>
            ))}
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="aspect-square border-2 border-dashed border-gray-200 rounded-xl flex flex-col items-center justify-center text-gray-400 hover:border-amber-400 hover:text-amber-500 transition-all bg-white"
            >
              <Camera size={24} />
              <span className="text-[10px] mt-2 font-bold uppercase">PNG Qo'shish</span>
            </button>
          </div>
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            multiple 
            accept="image/png, image/jpeg, image/webp" 
            className="hidden" 
          />
        </div>

        <div className="space-y-4">
          <Input label="Mahsulot Nomi" value={formData.name} onChange={v => setFormData({...formData, name: v})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Narx (Pinduoduo $)" type="number" value={formData.pinduoduoPrice || ''} onChange={v => setFormData({...formData, pinduoduoPrice: Number(v)})} />
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block">Katalog Narxi (3x)</label>
              <div className="bg-amber-50 border border-amber-100 p-4 rounded-2xl font-black text-amber-700 h-[56px] flex items-center">
                ${(formData.pinduoduoPrice || 0) * MARKUP_RATE}
              </div>
            </div>
          </div>
          <div>
            <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block mb-2 px-1">Kategoriya</label>
            <select 
              className="w-full bg-white border border-gray-100 rounded-2xl p-4 shadow-sm outline-none"
              value={formData.category}
              onChange={e => setFormData({...formData, category: e.target.value})}
            >
              {['Mebel', 'Oshxona', 'Aksessuarlar', 'Elektronika', 'Kiyim-kechak', 'Sport'].map(c => (
                <option key={c} value={c}>{c}</option>
              ))}
            </select>
          </div>
          <textarea 
            className="w-full bg-white border border-gray-100 rounded-2xl p-4 h-32 shadow-sm outline-none focus:ring-1 focus:ring-amber-500"
            placeholder="Mahsulot haqida batafsil ma'lumot..."
            value={formData.description}
            onChange={e => setFormData({...formData, description: e.target.value})}
          />
        </div>

        <button 
          onClick={handleSave}
          className="w-full py-4 gold-gradient text-white font-bold rounded-2xl shadow-premium flex items-center justify-center space-x-2 active:scale-95 transition-all"
        >
          <Save size={20} />
          <span>Saqlash</span>
        </button>
      </div>
    </div>
  );
};

