import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Home, 
  Search, 
  Grid, 
  User as UserIcon, 
  ShoppingCart, 
  Star, 
  ChevronLeft, 
  MessageCircle, 
  Share2, 
