const AdminPanel = ({ onAdd, onCancel }: any) => {
  const [formData, setFormData] = useState<Partial<Product>>({ name: '', pinduoduoPrice: 0, description: '', category: 'Mebel', images: [] });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: any) => {
    const files = e.target.files;
    if (!files) return;
    Array.from(files).forEach((file: any) => {
      const reader = new FileReader();
      reader.onloadend = () => setFormData(prev => ({ ...prev, images: [...(prev.images || []), reader.result as string] }));
      reader.readAsDataURL(file);
    });
  };

  return (
    <div className="p-8 pb-32 space-y-8 fade-in">
      <div className="flex items-center space-x-5">
        <button onClick={onCancel} className="w-10 h-10 bg-white border border-gray-100 rounded-xl flex items-center justify-center text-gray-400 shadow-sm"><ChevronLeft size={24} /></button>
        <h2 className="text-3xl font-bold tracking-tight">Yangi Mahsulot</h2>
      </div>

      <div className="space-y-8">
        <div className="space-y-4">
          <label className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em] block px-1">Mahsulot PNG Rasmlari</label>
          <div className="grid grid-cols-3 gap-4">
            {formData.images?.map((img, i) => (
              <div key={i} className="relative aspect-square rounded-[1.5rem] overflow-hidden group shadow-sm bg-gray-50 border border-gray-100 flex items-center justify-center p-3">
                <img src={img} className="max-w-full max-h-full object-contain" />
                <button onClick={() => setFormData({...formData, images: formData.images?.filter((_, idx) => idx !== i)})} className="absolute top-2 right-2 bg-black/60 text-white rounded-full p-1.5 opacity-0 group-hover:opacity-100 transition-opacity"><X size={12} /></button>
              </div>
            ))}
            <button onClick={() => fileInputRef.current?.click()} className="aspect-square border-2 border-dashed border-gray-200 rounded-[1.5rem] flex flex-col items-center justify-center text-gray-400 hover:border-amber-400 hover:text-amber-500 transition-all bg-white group">
              <Camera size={32} className="group-hover:scale-110 transition-transform" />
              <span className="text-[10px] mt-3 font-bold uppercase tracking-widest">PNG Qo'shish</span>
            </button>
          </div>
          <input type="file" ref={fileInputRef} onChange={handleFileChange} multiple accept="image/png" className="hidden" />
        </div>

        <div className="space-y-6">
          <Input label="Mahsulot Nomi" value={formData.name} onChange={(v:any) => setFormData({...formData, name: v})} />
          <div className="grid grid-cols-2 gap-5">
            <Input label="Narxi ($)" type="number" value={formData.pinduoduoPrice || ''} onChange={(v:any) => setFormData({...formData, pinduoduoPrice: Number(v)})} />
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block px-1">Platformadagi narxi</label>
              <div className="bg-amber-50 border border-amber-100 p-5 rounded-3xl font-black text-amber-700 h-[64px] flex items-center shadow-inner text-xl">
                ${(formData.pinduoduoPrice || 0) * MARKUP_RATE}
              </div>
            </div>
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block px-1">Kategoriya</label>
            <select className="w-full bg-white border border-gray-100 rounded-[1.5rem] p-5 shadow-sm outline-none focus:ring-2 focus:ring-amber-500 transition-all text-base appearance-none cursor-pointer" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})}>
              {['Mebel', 'Oshxona', 'Aksessuarlar', 'Elektronika', 'Kiyim-kechak', 'Sport', 'Go\'zallik'].map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
          <textarea className="w-full bg-white border border-gray-100 rounded-[1.5rem] p-6 h-40 shadow-sm outline-none focus:ring-2 focus:ring-amber-500 resize-none transition-all text-base" placeholder="Tavsif..." value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
        </div>

        <button onClick={() => onAdd(formData)} className="w-full py-5 gold-gradient text-white font-bold rounded-3xl shadow-premium flex items-center justify-center space-x-3 active:scale-[0.98] transition-all text-xl">
          <Save size={24} />
          <span>Saqlash</span>
        </button>
      </div>
    </div>
  );
};

