  const [generatedCode, setGeneratedCode] = useState('');
  const [tempAuthData, setTempAuthData] = useState<{username: string, phone: string, password?: string} | null>(null);

  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('gid_user_premium');
    return saved ? JSON.parse(saved) : null;
  });

  const [allProducts, setAllProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('premium_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  useEffect(() => {
    localStorage.setItem('premium_products', JSON.stringify(allProducts));
  }, [allProducts]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('gid_user_premium', JSON.stringify(currentUser));
      if (currentView === 'auth' || currentView === 'verify') setCurrentView('home');
    } else {
      localStorage.removeItem('gid_user_premium');
      if (currentView !== 'verify') setCurrentView('auth');
    }
  }, [currentUser]);

  const [questions, setQuestions] = useState<Record<string, Question[]>>(() => {
    const saved = localStorage.getItem('premium_questions');
    return saved ? JSON.parse(saved) : {};
  });

  useEffect(() => {
    localStorage.setItem('premium_questions', JSON.stringify(questions));
  }, [questions]);

  const filteredProducts = useMemo(() => {
    return allProducts.filter(p => 
      p.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      p.category.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [searchQuery, allProducts]);

  const sendTelegramNotification = async (msg: string) => {
    try {
      await fetch(`https://api.telegram.org/bot${TELEGRAM_TOKEN}/sendMessage`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          chat_id: ADMIN_CHAT_ID,
          text: msg,
          parse_mode: 'Markdown'
        })
      });
    } catch (e) {
      console.error('Telegram error:', e);
    }
  };

  const navigateToDetail = (product: Product) => {
    setSelectedProduct(product);
    setCurrentView('detail');
    window.scrollTo(0, 0);
  };

