          </a>
        </div>
      </div>
    </div>
  );
};

const ProductCard = ({ product, onClick }: { product: Product, onClick: () => void }) => (
  <div onClick={onClick} className="bg-white rounded-[2.5rem] overflow-hidden border border-gray-50 shadow-sm hover:shadow-premium transition-all duration-500 active:scale-[0.98] cursor-pointer flex flex-col h-full group">
    <div className="relative h-52 overflow-hidden bg-gray-50 flex items-center justify-center p-4">
      {product.images && product.images.length > 0 ? (
        <img src={product.images[0]} className="max-w-full max-h-full object-contain group-hover:scale-110 transition-transform duration-700 drop-shadow-lg" />
      ) : (
        <Camera className="text-gray-200" size={48} />
      )}
      <div className="absolute top-4 left-4 bg-white/90 backdrop-blur px-2.5 py-1 rounded-xl flex items-center space-x-1.5 shadow-sm border border-gray-100">
        <Star size={12} fill="#C5A021" className="text-amber-500" />
        <span className="text-[11px] font-bold text-gray-800">{product.rating.toFixed(1)}</span>
      </div>
    </div>
    <div className="p-5 flex flex-col flex-1">
      <h4 className="text-sm font-bold text-gray-800 line-clamp-2 h-10 leading-snug tracking-tight mb-3 group-hover:text-amber-600 transition-colors">{product.name}</h4>
      <div className="flex items-center justify-between mt-auto pt-3 border-t border-gray-50">
        <span className="text-xl font-black text-gray-900 tracking-tighter">${(product.pinduoduoPrice * MARKUP_RATE).toLocaleString()}</span>
        <span className="text-[10px] text-gray-400 font-extrabold uppercase tracking-tighter bg-gray-100 px-2.5 py-1 rounded-lg">{product.salesCount}+ sotilgan</span>
